  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-rel-007-gestao-parcerias-estrategicas';

  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index)
  VALUES
    (v_sop_id, 1, 'Objetivo', 'Estabelecer o processo completo de identificação, qualificação, formalização e ativação de parcerias estratégicas da TBO. O objetivo é construir um ecossistema de parceiros que amplifique o alcance comercial, gere indicações qualificadas e posicione a TBO como referência no mercado imobiliário de alto padrão. Parcerias ativas devem gerar valor mútuo — não são favores, são negócios.', 'step', 0),
    (v_sop_id, 2, 'Escopo', E'**Quem executa:** Ruy (Dir. Comercial) como responsável estratégico + Líder Comercial para operação\n**Quando se aplica:** Prospecção contínua de novos parceiros + Ativação por campanha/projeto\n**Tipos cobertos:** Comarketing, indicação mútua, co-criação de conteúdo, patrocínio de evento, parceria técnica\n**Limites:** Parceria com exclusividade ou joint-venture requer aprovação de Marco + assessoria jurídica', 'step', 1),
    (v_sop_id, 3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Identificação de parceiros | Ruy | Marco | Equipe Comercial | — |\n| Qualificação (fit) | Ruy | Marco | — | — |\n| Primeiro contato | Ruy | — | — | Marco |\n| Negociação do acordo | Ruy | Marco | Jurídico (se necessário) | — |\n| Formalização (MOU/Contrato) | Ruy | Marco | Jurídico | Financeiro |\n| Ativação de campanha conjunta | Lider Comercial | Ruy | Dir. Criativo | Marco |\n| Monitoramento de resultados | Lider Comercial | Ruy | — | Marco |\n| Revisão anual do portfólio | Ruy | Marco | — | Toda liderança |', 'step', 2),
    (v_sop_id, 4, 'Pré-requisitos', E'- Deck de apresentação da TBO atualizado (versão institucional + por BU)\n- Proposta de valor da parceria definida antes do primeiro contato\n- Pipeline de parceiros no CRM TBO OS\n- Modelo de MOU aprovado por Marco\n- Critérios de qualificação definidos (score 1-5 por dimensão)\n- Budget de comarketing aprovado para o trimestre (se parceria envolve investimento)', 'step', 3),
    (v_sop_id, 5, 'Procedimento', E'**FASE 1: Identificação e qualificação**\n1. Mapear parceiros por categoria: incorporadoras, arquitetos, agências complementares, fornecedores tech, influenciadores, associações\n2. Aplicar score de qualificação (5 dimensões × 1-5): Audiência, Reputação, Reciprocidade, Atividade, Relacionamento\n3. Avançar apenas com score ≥ 18/25\n4. Registrar no CRM TBO OS > Parceiros > Prospecção\n\n**FASE 2: Primeiro contato e proposta**\n1. Priorizar warm intro (conexão em comum)\n2. Mensagem de abertura: 3 linhas — personalização + proposta de valor + próximo passo\n3. Call exploratório de 20-30 min: entender objetivos deles, apresentar cases TBO, explorar valor mútuo\n4. Enviar proposta de parceria em até 48h (formato: 1 página)\n\n**FASE 3: Negociação e formalização**\n1. Máximo 2 rodadas de ajuste na negociação\n2. Formalizar via MOU (parcerias exploratórias) ou Contrato (com obrigações financeiras)\n3. Assinar digitalmente e arquivar no TBO OS > Contratos > Parcerias\n4. Mover parceiro no CRM: Prospecção → Parceiro Ativo\n5. Realizar onboarding do parceiro (equipe, materiais, canal de comunicação)\n\n**FASE 4: Ativação e execução**\n1. Criar briefing para cada iniciativa: objetivo, formato, responsabilidades, prazo, métricas\n2. Executar conforme briefing aprovado por ambos\n3. Registrar resultados no TBO OS (leads, alcance, negócios originados)\n4. Enviar relatório ao parceiro em até 5 dias úteis\n\n**FASE 5: Monitoramento e revisão**\n1. Revisão mensal: indicações geradas, próximas ações, saúde do relacionamento\n2. Revisão trimestral: parceiros dormentes (sem resultado em 90 dias) → reclassificar ou encerrar\n3. Identificar gaps e definir 3-5 novos parceiros para prospecção', 'step', 4),
    (v_sop_id, 6, 'Checklist de Validação', E'- [ ] Parceiro qualificado com score ≥ 18/25\n- [ ] Registrado no CRM TBO OS\n- [ ] Proposta enviada em até 48h após call\n- [ ] MOU ou Contrato assinado digitalmente e arquivado\n- [ ] Onboarding do parceiro realizado\n- [ ] Primeira ação planejada nos primeiros 30 dias\n- [ ] Resultados registrados após cada ação\n- [ ] Revisão mensal realizada\n- [ ] Parceiros dormentes tratados no ciclo trimestral', 'checkpoint', 5),
    (v_sop_id, 7, 'Ferramentas e Recursos', E'- **CRM**: TBO OS > Comercial > Pipeline de Parceiros\n- **Contratos**: TBO OS > Contratos > Parcerias\n- **Deck institucional**: Google Drive > Apresentações > Institucional\n- **Assinatura digital**: DocuSign ou similar\n- **Modelo de MOU**: Google Drive > Jurídico > Templates\n- **Template de proposta**: disponível no TBO OS > Knowledge > Relacionamentos', 'tip', 6),
    (v_sop_id, 8, 'SLAs e Métricas', E'- **Primeiro contato após qualificação**: até 5 dias úteis\n- **Proposta após call exploratório**: até 48h\n- **Formalização após acordo verbal**: até 15 dias\n- **Meta de parceiros ativos**: 10 a 20 (qualidade > quantidade)\n- **Meta de indicações por parceiro/trimestre**: ≥ 2 leads qualificados\n- **Meta de negócios via parceiros**: ≥ 20% do pipeline comercial\n- **Revisão do portfólio**: mensal (operacional) + trimestral (estratégica)\n- **Relatório de resultado de ação**: até 5 dias úteis após execução', 'note', 7),
    (v_sop_id, 9, 'Troubleshooting', E'**Parceiro ativo sem gerar resultados em 90 dias**\n→ Agendar conversa de alinhamento: o que mudou? há oportunidades no horizonte?\n→ Se sem perspectiva real: encerrar com gentileza, manter relacionamento pessoal\n→ Não manter parceiro ativo "por educação" — dilui foco\n\n**Parceiro quer mais do que pode oferecer**\n→ Ser direto sobre capacidade atual da TBO\n→ Propor escalonamento: começar pequeno, crescer com resultados\n\n**Conflito de interesse com cliente atual**\n→ Verificar cláusula de exclusividade antes de fechar parceria com concorrente do cliente\n→ Em caso de dúvida: consultar Marco antes de avançar\n\n**Parceiro usa marca TBO sem aprovação**\n→ Contatar imediatamente e solicitar remoção\n→ Revisar MOU para incluir cláusula de uso de marca', 'warning', 8),
    (v_sop_id, 10, 'Template: Proposta e Scoring de Parceria', E'**PROPOSTA DE PARCERIA TBO × [PARCEIRO]**\n```\nOBJETIVO: Ampliar alcance junto a [PÚBLICO] gerando [RESULTADO ESPERADO]\n\nO QUE A TBO OFERECE\n- [Benefício 1: indicação, conteúdo, desconto, visibilidade]\n- [Benefício 2]\n- [Benefício 3]\n\nO QUE ESPERAMOS\n- [Contrapartida 1]\n- [Contrapartida 2]\n\nPRIMEIRAS AÇÕES (90 dias)\n1. [Ação] — responsável: ___ | prazo: ___\n2. [Ação] — responsável: ___ | prazo: ___\n\nMÉTRICAS: ___ leads | ___ impressões | ___ projetos originados\nPRÓXIMO PASSO: Assinar MOU até ___/___/___\n```\n\n**SCORING DE QUALIFICAÇÃO**\n```\n| Dimensão       | Critério                                   | Score (1-5) |\n|----------------|--------------------------------------------|-------------|\n| Audiência       | Audiência deles é nosso ICP imobiliário?  |             |\n| Reputação       | Reforça posicionamento TBO premium?       |             |\n| Reciprocidade   | Entregam valor real para nós?             |             |\n| Atividade       | Ativos no mercado gerando negócios?       |             |\n| Relacionamento  | Temos ponto de entrada (warm intro)?      |             |\nTOTAL: ___ / 25\n✅ ≥18: Avançar | ⚠️ 12-17: Watchlist | ❌ <12: Descartar\n```', 'tip', 9)
