  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index)
  VALUES
    (v_sop_id, 1, 'Objetivo', 'Garantir que todo render produzido pela BU Digital 3D da TBO passe por um processo estruturado de controle de qualidade antes da entrega ao cliente. O CQ protege a reputação da TBO, reduz retrabalho e assegura consistência técnica e criativa entre as entregas. A aprovação de qualidade é etapa obrigatória — nenhum render é entregue sem passar por este processo.', 'step', 0),
    (v_sop_id, 2, 'Escopo', E'**Quem executa:** Líder de D3D (revisão principal) + segundo revisor (par) para itens críticos\n**Quando se aplica:** Todo render produzido pela TBO, independente de prazo ou volume\n**Tipos cobertos:** Renders still, ambientes, tours virtuais (frames-chave), fachada, implantação\n**Limites:** Este SOP cobre imagens estáticas. Animações/vídeos têm SOP próprio (tbo-av-006).', 'step', 1),
    (v_sop_id, 3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Produção do render | Artista 3D | Líder D3D | — | — |\n| Auto-revisão (artista) | Artista 3D | — | — | Líder D3D |\n| Revisão técnica | Líder D3D | — | Artista 3D | — |\n| Revisão criativa | Dir. Criativo (Marco) | — | Líder D3D | — |\n| Aprovação final | Líder D3D | Marco (projetos premium) | — | Atendimento |\n| Entrega ao cliente | Atendimento | Líder D3D | — | Marco |', 'step', 2),
    (v_sop_id, 4, 'Pré-requisitos', E'- Briefing criativo do projeto lido e compreendido pelo artista\n- Referências visuais disponíveis (moodboard aprovado)\n- Resolução final e formato de entrega definidos no briefing\n- Arquivo de cena 3D completo e atualizado\n- Nomenclatura de arquivo seguindo padrão TBO\n- Monitor calibrado (sRGB para web, AdobeRGB para impressão)', 'step', 3),
    (v_sop_id, 5, 'Procedimento', E'**Etapa 1: Auto-revisão do artista**\nAntes de enviar para QC, checar: resolução/aspecto ratio, naming correto, sem artefatos óbvios, composição confere com câmera aprovada, configurações finais de render.\n\n**Etapa 2: Revisão Técnica (Líder D3D)**\n- Iluminação: sem queima de altas, sem crush de sombras, distribuição coerente com briefing\n- Materiais: todos especificados aplicados, texturas em resolução, reflexos coerentes\n- Geometria: sem clipping, sem z-fighting, proporções em escala humana\n- Vegetação/Contexto: variedade de espécies, pessoas/veículos em escala, céu coerente\n- Artefatos: sem fireflies, grain excessivo, banding ou sombras fantasma\n\n**Etapa 3: Revisão Criativa (Líder D3D / Marco)**\n- Alinhamento com briefing: conceito e emoção comunicados, paleta alinhada\n- Composição: ponto focal claro, profundidade de campo intencional, sem distrações\n- Staging: mobiliário e decoração condizentes com público-alvo, humanizado e aspiracional\n- Fidelidade: planta baixa seguida, acabamentos especificados presentes\n\n**Etapa 4: Aprovação e Registro**\n1. Preencher checklist QC assinado pelo Líder D3D\n2. Registrar status "Aprovado QC" no TBO OS\n3. Gerar versões de entrega: Web (JPG 85%, sRGB), Impressão (TIFF 300dpi, AdobeRGB), Social\n4. Nomear arquivos finais seguindo padrão TBO\n5. Upload na pasta do cliente (Google Drive ou Wetransfer)\n6. Comunicar Atendimento para coordenar entrega', 'step', 4),
    (v_sop_id, 6, 'Checklist de Validação', E'**TÉCNICO**\n- [ ] Resolução e aspecto ratio corretos\n- [ ] Sem fireflies ou grain excessivo\n- [ ] Iluminação sem queima ou crush\n- [ ] Materiais especificados aplicados\n- [ ] Sem clipping de geometria visível\n- [ ] Texturas sem pixelização\n- [ ] Céu e contexto coerentes com briefing\n- [ ] Nomenclatura de arquivo correta\n\n**CRIATIVO**\n- [ ] Conceito e emoção do briefing comunicados\n- [ ] Paleta alinhada ao posicionamento\n- [ ] Composição com ponto focal claro\n- [ ] Staging humanizado e aspiracional\n- [ ] Planta baixa seguida fielmente\n- [ ] Acabamentos especificados presentes\n\n**OPERACIONAL**\n- [ ] Versões de entrega geradas (web + impressão + social)\n- [ ] Status atualizado no TBO OS\n- [ ] Upload na pasta do cliente\n- [ ] Atendimento notificado', 'checkpoint', 5),
    (v_sop_id, 7, 'Ferramentas e Recursos', E'- **Render Engine**: Vray, Corona, Lumion (conforme projeto)\n- **Pós-produção**: Photoshop (ajustes finais e compositing)\n- **Calibração de monitor**: ferramentas de perfil de cor do SO (sRGB / AdobeRGB)\n- **Gestão**: TBO OS > Projetos > D3D\n- **Entrega**: Google Drive (pasta do cliente) ou Wetransfer\n- **Referências de qualidade**: Google Drive > D3D > QC References\n- **Histórico aprovados**: Google Drive > D3D > Arquivo > Aprovados', 'tip', 6),
    (v_sop_id, 8, 'SLAs e Métricas', E'- **Auto-revisão do artista**: 30-60 min por render antes de enviar para QC\n- **Revisão técnica (Líder D3D)**: máx. 2h por render em projetos standard\n- **Revisão criativa**: máx. 1h por render\n- **Taxa de aprovação no primeiro QC**: meta ≥ 85%\n- **Taxa de retrabalho pós-entrega ao cliente**: meta ≤ 15%\n- **Resolução mínima web**: 3000px no lado maior\n- **Resolução impressão**: 300 dpi no tamanho final\n- **Máx. ciclos internos de revisão**: 2 — após isso, escalar para Marco', 'note', 7),
    (v_sop_id, 9, 'Troubleshooting', E'**Render com fireflies excessivos**\n→ Aumentar samples de render (não mascarar com pós-processo)\n→ Verificar materiais emissivos com intensidade muito alta\n→ Se prazo crítico: Photoshop healing brush + documentar como exceção\n\n**Materiais errados (cor ou acabamento diverge do projeto)**\n→ Retornar ao artista com referência específica\n→ Se foi interpretação livre: alinhar com atendimento/cliente antes de re-produzir\n\n**Cliente solicita alteração após aprovação interna**\n→ Avaliar: ajuste de qualidade (TBO absorve) ou mudança de escopo (gera adição)\n→ Se escopo: acionar Atendimento para formalizar (SOP tbo-atd-003)\n\n**Prazo apertado pressiona o QC**\n→ Nunca pular o checklist — reduzir tempo de outros processos, não do QC\n→ Escalar para Marco se prazo inviabiliza qualidade mínima aceitável\n→ Se necessário: entregar câmeras prioritárias com comunicado sobre o restante', 'warning', 8),
    (v_sop_id, 10, 'Template: Nomenclatura e Checklist QC Impresso', E'**PADRÃO DE NOMENCLATURA D3D TBO**\n```\nPRODUÇÃO:\n[PROJETO]_[AMBIENTE]_[CAM##]_v[##].png\nEx: MIRALTO_SALA-ESTAR_CAM01_v03.png\n    BOSQUE_FACHADA-FRENTE_CAM01_v01.png\n\nENTREGA FINAL:\n[PROJETO]_[AMBIENTE]_[CAM##]_FINAL_WEB.jpg      → 3000px+, sRGB, JPG85%\n[PROJETO]_[AMBIENTE]_[CAM##]_FINAL_PRINT.tif    → 300dpi, AdobeRGB\n[PROJETO]_[AMBIENTE]_[CAM##]_FINAL_SOCIAL.jpg   → conforme plataforma\n\nCÓDIGOS DE AMBIENTE\nSALA-ESTAR | SALA-JANTAR | COZINHA | SUITE-MASTER | SUITE-01\nVARANDA | FACHADA-FRENTE | FACHADA-LATERAL | IMPLANTACAO\nLOBBY | ROOFTOP | PISCINA | FITNESS | COWORKING\n```\n\n**CHECKLIST QC — VERSÃO IMPRESSA**\n```\nPROJETO: _______ | AMBIENTE: _______ | CAM: ___ | DATA: ___/___/___\nARTISTA: ______________ | REVISOR: ______________\n\nTÉCNICO\n[ ] Resolução/aspecto ratio ✓    [ ] Sem fireflies/noise ✓\n[ ] Iluminação balanceada ✓      [ ] Materiais corretos ✓\n[ ] Sem clipping geometria ✓     [ ] Texturas em resolução ✓\n[ ] Contexto externo coerente ✓  [ ] Nomenclatura correta ✓\n\nCRIATIVO\n[ ] Conceito briefing ✓          [ ] Paleta alinhada ✓\n[ ] Ponto focal claro ✓          [ ] Staging humanizado ✓\n[ ] Planta baixa seguida ✓       [ ] Acabamentos presentes ✓\n\nOPERACIONAL\n[ ] Versões geradas ✓            [ ] Status TBO OS ✓\n[ ] Upload pasta cliente ✓       [ ] Atendimento notificado ✓\n\nRESULTADO: [ ] APROVADO  [ ] REPROVADO\nMotivo reprovação: ________________________________________\nAssinatura Líder D3D: __________________ Data: ___/___/___\n```', 'tip', 9)
